const snapshotAt = new Date().toISOString();
const repoRoot = $env.PCP_REPO_ROOT || '/opt/saars.inplast';
const workbookPath = $env.PCP_ALMOX_WORKBOOK || '/data/ingest/Estoque Almoxarifado.xlsx';
return [
  {
    json: {
      source_code: 'estoque_materia_prima_almoxarifado',
      parser_path: `${repoRoot}/parsers/parse_estoque_almoxarifado_mp.py`,
      runner_path: `${repoRoot}/parsers/run_inventory_parser.py`,
      workbook_path: workbookPath,
      snapshot_at: snapshotAt,
      workflow_name: 'PCP | 12 | Almoxarifado | Ingestao'
    }
  },
  {
    json: {
      source_code: 'estoque_componente_almoxarifado',
      parser_path: `${repoRoot}/parsers/parse_estoque_almoxarifado_componentes.py`,
      runner_path: `${repoRoot}/parsers/run_inventory_parser.py`,
      workbook_path: workbookPath,
      snapshot_at: snapshotAt,
      workflow_name: 'PCP | 12 | Almoxarifado | Ingestao'
    }
  }
];

const raw = ($json.stdout || '').trim();
if (!raw) {
  throw new Error('Parser nao retornou saida. Source: ' + ($json.source_code || 'unknown') + '. Stderr: ' + ($json.stderr || '(vazio)'));
}
let payload;
try {
  payload = JSON.parse(raw);
} catch (parseError) {
  const lines = raw.split('\n').filter(line => line.trim());
  let parsed = false;
  for (let i = lines.length - 1; i >= 0; i--) {
    try {
      payload = JSON.parse(lines[i]);
      parsed = true;
      break;
    } catch (e) { /* try previous line */ }
  }
  if (!parsed) {
    throw new Error('Falha ao interpretar JSON do parser. Saida (primeiros 500 chars): ' + raw.slice(0, 500) + ' | Stderr: ' + ($json.stderr || '(vazio)'));
  }
}
return [{ json: payload }];

const esc = (value) => {
  const raw = JSON.stringify(value ?? {});
  return raw.replace(/\\/g, '\\\\').replace(/'/g, "''");
};
const escText = (value) => String(value ?? '').replace(/\\/g, '\\\\').replace(/'/g, "''");
const sql = `select ops.ingest_inventory_payload(\n  '${escText($json.source_code)}',\n  '${escText($json.snapshot_at)}'::timestamptz,\n  '${esc($json.records)}'::jsonb,\n  '${esc($json.meta)}'::jsonb\n) as run_id;`;
return [{ json: { ...$json, sql_query: sql } }];

const dbRows = $json;
return [{
  json: {
    status: 'ok',
    db_result: dbRows,
    note: 'Configure as credenciais do node Postgres antes do primeiro uso.'
  }
}];
